#!/usr/bin/env node

const process = require('node:process');
const fs = require('node:fs');
const path = require('node:path');
const archiver = require('archiver');
const loaderUtils = require('loader-utils');
const { optimize } = require('svgo');

const topomatic360 = 'https://360.topomatic.ru';
const debugPort = 9091;

function printDebugInfo(port) {
    const extension = `http://localhost:${port}`;
    console.log(`\n  ➜ \u001b[1;32m\u001b[1;1mDebug  \u001b[1;0m\t\u001b[1;33m${topomatic360}?extensionDevelopmentPath=${encodeURIComponent(extension)}\u001b[1;0m`);
    console.log(`  ➜ \u001b[1;32m\u001b[1;1mInstall\u001b[1;0m\t\u001b[1;33m${topomatic360}?extensionInstallPath=${encodeURIComponent(extension)}\u001b[1;0m`);
    console.log(`  ➜ \u001b[1;32m\u001b[1;1mLocal  \u001b[1;0m\t\u001b[1;33m${extension}\u001b[1;0m\n`);
}

async function serveVite() {
    console.log('Serve in vite mode');
    const vite = await import('vite');
    const vuePlugin = (await import('@vitejs/plugin-vue')).default;
    const viteServer = await vite.createServer({
        mode: 'development',
        server: {
            cors: true,
            port: debugPort,
        },
        plugins: [
            vuePlugin(),
        ],
        build: {
            rollupOptions: {
                external: ['vue'],
                output: {
                    globals: {
                        vue: 'Vue'
                    }
                },
            },
        },
    });
    await viteServer.listen();
    printDebugInfo(viteServer.config.server.port);
}

function resolvePackage(fs) {
    const fileName = path.join(__dirname, 'package.json');
    const pkg = fs.readFileSync(fileName, 'utf8');
    return JSON.parse(pkg);
}

function emitFile(fileName, data) {
    fileName = `dist/${fileName}`;
    console.log(fileName);
    const dist = path.join(path.resolve('.'), fileName);
    const dirname = path.dirname(dist);
    fs.mkdirSync(dirname, {
        recursive: true,
    });
    fs.writeFileSync(dist, data);
}

function hashName(name, hash) {
    const index = name.lastIndexOf('.');
    if (index < 0) {
        return name;
    } else {
        return `${name.substring(0, index)}-${hash.substring(0, 8)}${name.substring(index)}`;
    }
}

function l10n(source) {
    let value = typeof source === 'string' ? JSON.parse(source) : source;
    for (const key in value) {
        if (value[key] === null) {
            delete value[key];
        }
    }
    value = JSON.stringify(value)
        .replace(/\u2028/g, '\\u2028')
        .replace(/\u2029/g, '\\u2029');
    return `${value}`;
}

function pipeApx(dir, prefix, archive) {
    const entries = fs.readdirSync(dir);
    for (const entry of entries) {
        const fileName = path.join(dir, entry);
        const stat = fs.statSync(fileName);
        const name = `${prefix}/${entry}`;
        if (stat.isFile()) {
            const item = fs.createReadStream(fileName);
            archive.append(item, {
                name,
            });
        } else {
            pipeApx(fileName, name, archive);
        }
    }
}

async function buildVite() {
    const albatros = resolvePackage(fs);
    const vite = await import('vite');
    const vuePlugin = (await import('@vitejs/plugin-vue')).default;
    const dirname = path.resolve('.');
    const fileName = path.join(dirname, 'package.json');
    let pkg = JSON.parse(fs.readFileSync(fileName, 'utf8'));
    const id = pkg.name;
    const main = pkg.main;
    delete pkg['$schema'];
    pkg = {
        ...pkg,
        name: pkg.name ?? path.basename(dirname),
        sdk: pkg.sdk === '${version}' ? albatros.version : pkg.sdk,
        buildSdk: albatros.version,
        buildDate: new Date().toLocaleString('en-En', {
            timeZone: 'UTC',
            timeZoneName: 'short',
            hour12: false,
        }),
    };
    console.log('\nBuild apx ' + id);
    const config = vite.defineConfig({
        define: {
            'process.env.NODE_ENV': JSON.stringify('production'),
        },
        plugins: [
            vuePlugin(),
        ],
        build: {
            emptyOutDir: true,
            chunkSizeWarningLimit: 10000,
            lib: {
                entry: path.join(dirname, main),
                formats: ['es'],
                name: 'index',
            },
            minify: true,
            manifest: false,
            rollupOptions: {
                external: ['vue'],
                output: {
                    globals: {
                        vue: 'Vue'
                    }
                },
                output: {
                    assetFileNames: 'css/[name]-[hash][extname]',
                    entryFileNames: 'js/[name]-[hash].mjs',
                },
            },
        },
        base: './',
        mode: 'production',
    });
    const result = await vite.build(config);
    for (let i = 0; i < result.length; i++) {
        const br = result[i].output;
        for (let i = 0; i < br.length; i++) {
            const item = br[i];
            if (item.isEntry) {
                pkg.main = item.fileName;
            }
        }
    }

    const assetCss = {};
    try {
        const cssPath = path.join(dirname, 'dist', 'css');
        const csss = fs.readdirSync(cssPath);
        for (const css of csss) {
            const fileName = path.join(cssPath, css);
            const stat = fs.statSync(fileName);
            if (stat.isFile()) {
                const key = css.substring(0, css.lastIndexOf('-')) + css.substring(css.lastIndexOf('.'));
                assetCss[key] = path.join('css', css);
            }
        }
    } catch (_) { }

    const encoding = new TextEncoder();
    const assetIcons = {};
    try {
        const icons = fs.readdirSync(path.join(dirname, 'icons'));
        for (const icon of icons) {
            const fileName = path.join(dirname, 'icons', icon);
            const stat = fs.statSync(fileName);
            if (stat.isFile()) {
                const data = fs.readFileSync(fileName);
                try {
                    const svg = optimize(data, {
                        multipass: true,
                        path: fileName
                    });
                    if (svg.data !== undefined) {
                        const data = encoding.encode(svg.data);
                        const hash = loaderUtils.getHashDigest(data, 'sha1', 'base62', Number.MAX_SAFE_INTEGER);
                        const assetPath = path.join('icons', hashName(icon, hash));
                        emitFile(assetPath, svg.data);
                        assetIcons[icon] = assetPath;
                    } else if (svg.error !== undefined) {
                        console.error(svg.error);
                    }
                } catch (e) {
                    console.warn(new Error(`Icon '${icon}' is not SVG`));
                    console.warn(e);
                }
            }
        }
    } catch (_) { }

    const assetLocales = {};
    try {
        const locales = fs.readdirSync(path.join(dirname, 'locales'));
        for (const locale of locales) {
            const fileName = path.join(dirname, 'locales', locale);
            const stat = fs.statSync(fileName);
            if (stat.isFile()) {
                const data = fs.readFileSync(fileName, 'utf8');
                try {
                    const localeFile = `${locale.substring(0, locale.lastIndexOf('.'))}.json`;
                    const localeSrc = l10n(data);
                    const hash = loaderUtils.getHashDigest(encoding.encode(localeSrc), 'sha1', 'base64', Number.MAX_SAFE_INTEGER);
                    const assetPath = path.join('locales', hashName(localeFile, hash));
                    emitFile(assetPath, localeSrc);
                    assetLocales[locale] = assetPath;
                } catch (e) {
                    console.error(new Error(`Invalid locale '${locale}'`));
                    console.error(e);
                }
            }
        }
    } catch (_) { }

    pkg.assets = {
        icons: assetIcons,
        locales: assetLocales,
        css: assetCss,
    }
    emitFile('package.json', JSON.stringify(pkg), null);

    if (pkg.apx) {
        return new Promise(resolve => {
            const apxDir = path.join(dirname, 'apx');
            if (fs.existsSync(apxDir)) {
                fs.rmSync(apxDir, {
                    recursive: true,
                });
            }
            fs.mkdirSync(apxDir);
            const apxPath = path.join(apxDir, `${id}.apx`);
            const stream = fs.createWriteStream(apxPath);
            let closed = false;
            stream.on('close', () => {
                if (!closed) {
                    closed = true;
                    resolve();
                }
            });
            const archive = new archiver('zip', {
                zlib: {
                    level: 9,
                },
            });
            archive.pipe(stream);
            pipeApx(path.join(dirname, 'dist'), '', archive);
            archive.finalize();
        });
    }
}

async function build() {
    await buildVite();
}

async function serve() {
    await serveVite();
}

async function main() {
    switch (process.argv[2]) {
        case 'serve':
            await serve();
            break;
        case 'build':
            await build();
            break;
        default:
            console.error(`Undefined command ${process.argv[2]}`);
            break;
    }
}

main();
